script.text:
      /* <flatten type="Javascript"> */
function load$CheckingReport$(g) {
  g._$k = [];
  g._$u = [];
  g._$i = g._getColumnOrder('stt');
  g._$d = g._getColumnOrder('ma_dvcs');
  g._$t = g._getColumnOrder('tag');
  g.add_onResponseComplete(on$GridReport$ResponseComplete);
  g.add_commandEvent(on$GridReport$ExecuteCommand);
}

function dispose$CheckingReport$(g) {
  g._$k = g._$u = g._$i = g._$d = g._$t = null;
  try {g.remove_commandEvent(on$GridReport$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridReport$ResponseComplete);} catch (ex) {}
}
function scatter$GridReport$(g){
  fill$Grid(g, true);
  if (g._rowCount > 0){
    g._activeRow = g._rowCount;
    g._activeColumn = g._$t;
    g._activeCell = g._getItem(g._activeRow, g._activeColumn);
	}
}
function on$GridReport$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender;
  switch (action) {
    case 'CreateTrans':
      request$Transaction(g, '1');
      break;
    case 'DeleteTrans':
      request$Transaction(g, '9');
      break;
    default:
      break;
  }
}
function on$GridReport$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object;
  switch (context) {
    case 'Transaction':
      if (result[0].Value != '') $message.show(result[1].Value, String.format('$find(\'{0}\')._focusWhenTabChanged();', g.get_id()));
        else {
          g._$k = [];
          g._$u = [];
          g.goToPage(-1);
        }
      break;
    default:
      break;
  }
}
function request$Transaction(g, t) {
  if (g._rowCount == 0) return;
  var r = (g._activeCell ? g._activeRow : 1), s = g._$k.join(',') + ',', su = g._$u.join(',') + ',', o = g._getItemValue(r, g._$t);
  o.row = r;
  if (isCheck$Grid(g)) g.request(o, 'Transaction', 'Transaction', [['ky', 'Decimal', g._period], ['nam', 'Decimal', g._year], ['ma_dvcs', 'String', g._unit], ['s', 'Infinite', s], ['su', 'Infinite', su], ['type', 'String', t]]);
}

function isCheck$Grid(g) {
  var msg = (g._language == 'v' ? 'Chưa có bản ghi nào được chọn, phải đánh dấu trước khi thực hiện chức năng này.' : 'No record selected, please select at least one record to process.');
  if (g._$k.length == 0) {
    $message.show(msg, String.format('$find(\'{0}\')._focusWhenTabChanged();', g.get_id()));
    return false;
  }
  return true;
}
function fill$Grid(g, f) {
  if (f && g._$k.length == 0) return;
  for (var r = 1; r <= g._rowCount; r++) {
    var k = row$Key(g, r, g._$i), i = Array.indexOf(g._$k, k);
    g._setItemValue(r, g._$t, (i > -1));
  }
}
function init$ExportKey(g, c) {
  var p = (c ? c : ''), keys = p + g._$k.join(',') + p, v = g._filterMemvars, i = $func.findMemvarIndex(g._$f, v);
  if (i > -1) {
    var memvar = v[i];
    memvar.NewValue = memvar.Compressed ? $func.compress(keys) : keys;
  }
}
function toggle$Grid(o) {
  var c = o.parentNode.parentNode.parentNode.id, g = $find($func.left(c, c.length - 11));
  for (var r = 1; r <= g._rowCount; r++) {
    if (!g._getItem(r, g._$t).disabled) {
      var k = row$Key(g, r, g._$i), p = row$Key(g, r, g._$d), i = Array.indexOf(g._$k, k);
      if (i == -1) Array.add(g._$k, k), Array.add(g._$u, p);
        else Array.removeAt(g._$k, i), Array.removeAt(g._$u, i);
      g._setItemValue(r, g._$t, (i == -1));
    }
  }

  init$ExportKey(g);
  if (g._rowCount <= 0) return;
  else {
    g._activeRow = g._rowCount;
    g._activeColumn = g._$t;
    g._activeCell = g._getItem(g._activeRow, g._activeColumn);
    g._focusWhenTabChanged();
  }
}
function onChange$SelectedValue(o) {
  var a = o.id.split('_inputCell_'), g = o.grid;
  if (!g) g = $find(a[0]);
  var r = $func.getLocationCell(o)[0], k = row$Key(g, r, g._$i), p = row$Key(g, r, g._$d), i = Array.indexOf(g._$k, k);
  if (i == -1) Array.add(g._$k, k), Array.add(g._$u, p);
    else Array.removeAt(g._$k, i), Array.removeAt(g._$u, i);

  init$ExportKey(g);
  g._activeRow = a[1].split('.')[0];
  g._activeColumn = a[1].split('.')[1];
  g._activeCell = g._getItem(g._activeRow, g._activeColumn);
}
function row$Key(g, r, c) {return g._getItemValue(r, c);}
/* </flatten> */
      &JavascriptReportInit;
